package com.cho2hand.marketplace.controller.chat; import com.cho2hand.marketplace.dto.chat.*; import com.cho2hand.marketplace.service.chat.ChatService; import jakarta.validation.Valid; import jakarta.validation.constraints.Positive; import java.util.List; import org.springframework.http.HttpStatus; import org.springframework.security.core.annotation.AuthenticationPrincipal; import org.springframework.web.bind.annotation.*;
@RestController @RequestMapping("/api/v1") public class ChatController {private final ChatService service;public ChatController(ChatService s){service=s;}@PostMapping("/listings/{listingId}/conversations")@ResponseStatus(HttpStatus.CREATED)public Long open(@AuthenticationPrincipal Long user,@PathVariable @Positive Long listingId){return service.open(user,listingId);}@GetMapping("/conversations")public List<ConversationResponse> conversations(@AuthenticationPrincipal Long user){return service.conversations(user);}@PostMapping("/conversations/{id}/messages")@ResponseStatus(HttpStatus.CREATED)public MessageResponse send(@AuthenticationPrincipal Long user,@PathVariable @Positive Long id,@Valid @RequestBody SendMessageRequest request){return service.send(user,id,request);}@GetMapping("/conversations/{id}/messages")public List<MessageResponse> messages(@AuthenticationPrincipal Long user,@PathVariable @Positive Long id){return service.messages(user,id);}}
